class DeepLinkHandler extends StatefulWidget {
  @override
  _DeepLinkHandlerState createState() => _DeepLinkHandlerState();
}

class _DeepLinkHandlerState extends State<DeepLinkHandler> {
  StreamSubscription? _linkSubscription;
  String _latestLink = 'No deep link received';
  String _latestAction = 'Waiting for deep link...';

  @override
  void initState() {
    super.initState();
    _initDeepLinkListener();
    _handleInitialLink();
  }

  Future<void> _initDeepLinkListener() async {
    _linkSubscription = linkStream.listen((String? link) {
      if (link != null) {
        _handleDeepLink(link);
      }
    }, onError: (err) {
      setState(() {
        _latestAction = 'Error: $err';
      });
    });
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        _handleDeepLink(initialLink);
      }
    } on PlatformException {
      setState(() {
        _latestAction = 'Failed to get initial link';
      });
    }
  }

  void _handleDeepLink(String link) {
    setState(() {
      _latestLink = link;
    });

    final uri = Uri.parse(link);
    final scheme = uri.scheme;
    final host = uri.host;
    final pathSegments = uri.pathSegments;
    final queryParams = uri.queryParameters;

    if (scheme == 'myapp') {
      if (pathSegments.isEmpty) {
        _navigateToHome();
        return;
      }

      final action = pathSegments[0];

      switch (action) {
        case 'profile':
          _handleProfileLink(pathSegments, queryParams);
          break;
        case 'payment':
          _handlePaymentLink(pathSegments, queryParams);
          break;
        case 'product':
          _handleProductLink(pathSegments, queryParams);
          break;
        case 'category':
          _handleCategoryLink(pathSegments, queryParams);
          break;
        case 'campaign':
          _handleCampaignLink(pathSegments, queryParams);
          break;
        default:
          _handleUnknownLink(action);
      }
    } else {
      setState(() {
        _latestAction = 'Invalid scheme: $scheme';
      });
    }
  }

  void _handleProfileLink(List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.length > 1) {
      final userId = pathSegments[1];
      final tab = queryParams['tab'] ?? 'overview';
      
      setState(() {
        _latestAction = 'Navigating to profile $userId (tab: $tab)';
      });

      Navigator.push(
        context,
        MaterialPageRoute(
          builder: (context) => ProfilePage(
            userId: userId,
            tab: tab,
            source: queryParams['source'],
          ),
        ),
      );
    } else {
      setState(() {
        _latestAction = 'Invalid profile link - missing user ID';
      });
    }
  }

  void _handlePaymentLink(List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.length > 1) {
      final action = pathSegments[1];
      
      if (action == 'confirm') {
        final orderId = queryParams['orderId'];
        final amount = queryParams['amount'];
        final currency = queryParams['currency'] ?? 'USD';
        
        setState(() {
          _latestAction = 'Navigating to payment confirmation (Order: $orderId)';
        });

        Navigator.push(
          context,
          MaterialPageRoute(
            builder: (context) => PaymentPage(
              action: 'confirm',
              orderId: orderId,
              amount: amount,
              currency: currency,
              source: queryParams['source'],
            ),
          ),
        );
      } else if (action == 'success') {
        final transactionId = queryParams['transactionId'];
        
        setState(() {
          _latestAction = 'Payment success: $transactionId';
        });

        Navigator.push(
          context,
          MaterialPageRoute(
            builder: (context) => PaymentPage(
              action: 'success',
              transactionId: transactionId,
            ),
          ),
        );
      } else if (action == 'failed') {
        final reason = queryParams['reason'] ?? 'Unknown error';
        
        setState(() {
          _latestAction = 'Payment failed: $reason';
        });

        Navigator.push(
          context,
          MaterialPageRoute(
            builder: (context) => PaymentPage(
              action: 'failed',
              errorReason: reason,
            ),
          ),
        );
      }
    } else {
      setState(() {
        _latestAction = 'Invalid payment link';
      });
    }
  }

  void _handleProductLink(List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.length > 1) {
      final productId = pathSegments[1];
      final campaignId = queryParams['campaign'];
      final referrer = queryParams['ref'];
      
      setState(() {
        _latestAction = 'Navigating to product $productId (campaign: $campaignId, ref: $referrer)';
      });

      Navigator.push(
        context,
        MaterialPageRoute(
          builder: (context) => ProductPage(
            productId: productId,
            campaignId: campaignId,
            referrer: referrer,
          ),
        ),
      );
    }
  }

  void _handleCategoryLink(List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.length > 1) {
      final categoryId = pathSegments[1];
      final sort = queryParams['sort'] ?? 'popular';
      final filter = queryParams['filter'];
      
      setState(() {
        _latestAction = 'Navigating to category $categoryId (sort: $sort)';
      });

      Navigator.push(
        context,
        MaterialPageRoute(
          builder: (context) => CategoryPage(
            categoryId: categoryId,
            sort: sort,
            filter: filter,
          ),
        ),
      );
    }
  }

  void _handleCampaignLink(List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.length > 1) {
      final campaignId = pathSegments[1];
      final utmSource = queryParams['utm_source'];
      final utmMedium = queryParams['utm_medium'];
      final utmCampaign = queryParams['utm_campaign'];
      
      setState(() {
        _latestAction = 'Campaign: $campaignId (source: $utmSource, medium: $utmMedium)';
      });

      Navigator.push(
        context,
        MaterialPageRoute(
          builder: (context) => CampaignPage(
            campaignId: campaignId,
            utmSource: utmSource,
            utmMedium: utmMedium,
            utmCampaign: utmCampaign,
          ),
        ),
      );
    }
  }

  void _handleUnknownLink(String action) {
    setState(() {
      _latestAction = 'Unknown action: $action';
    });
  }

  void _navigateToHome() {
    setState(() {
      _latestAction = 'Navigating to home';
    });
    Navigator.pushReplacementNamed(context, '/home');
  }

  @override
  void dispose() {
    _linkSubscription?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Deep Link Handler'),
      ),
      body: Padding(
        padding: EdgeInsets.all(16.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(
              'Latest Deep Link:',
              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
            ),
            SizedBox(height: 8),
            Text(_latestLink),
            SizedBox(height: 24),
            Text(
              'Action:',
              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
            ),
            SizedBox(height: 8),
            Text(_latestAction),
            SizedBox(height: 32),
            Text(
              'Supported Deep Links:',
              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
            ),
            SizedBox(height: 8),
            _buildExampleLink('myapp://profile/123?tab=posts&source=notification'),
            _buildExampleLink('myapp://payment/confirm?orderId=ABC123&amount=99.99&currency=USD'),
            _buildExampleLink('myapp://payment/success?transactionId=TXN456'),
            _buildExampleLink('myapp://product/789?campaign=summer2024&ref=email'),
            _buildExampleLink('myapp://category/electronics?sort=price&filter=sale'),
            _buildExampleLink('myapp://campaign/flash-sale?utm_source=push&utm_medium=notification'),
          ],
        ),
      ),
    );
  }

  Widget _buildExampleLink(String link) {
    return Padding(
      padding: EdgeInsets.symmetric(vertical: 4),
      child: Text(
        '• $link',
        style: TextStyle(fontSize: 12, color: Colors.blue),
      ),
    );
  }
}

